"""
MKT Original — Luke all 24 chapters
Output: data/commentary/mkt-original/luke.json

Luke is the most polished Greek of the Gospels (Attic literary flourishes,
periodic sentences, medical vocabulary). Key terms: soteria/soter
(salvation/savior — most common in Luke-Acts), afesis (forgiveness/release),
ekporeuomai (goes out), paraballo (Luke\'s parables terminology),
anabainō eis Ierousalem (the travel narrative verb), anastasis, euangelizō.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

